// // When sel is 0, perform bitwise NOT on A; when sel is 1, perform XOR on A and B
module top_module(
    input [7:0] A,
    input [7:0] B,
    input sel,
    output reg [7:0] C
    );always @(*) begin
        if(sel == 0)
            C = A ^ B;
        else
            C = ~A;
    end

endmodule
